1	// COR24 APL Interpreter -- Number I/O
2	// Integer to/from decimal string with APL underscore-negative convention.
3	
4	#pragma once
5	
6	#include "io.h"
7	
8	// Parse a decimal integer from a string.
9	// APL convention: underscore prefix for negative (_42 means -42).
10	// Returns the parsed value. Sets *end to index past last digit consumed.
11	// If no digits found, *end is set to start position.
12	int parse_int(char *s, int start, int *end) {
13	    int i = start;
14	    int neg = 0;
15	    int val = 0;
16	    int got = 0;
17	
18	    // Check for underscore-negative prefix
19	    if (s[i] == 95) {
20	        neg = 1;
21	        i++;
22	    }
23	
24	    // Parse digits
25	    while (s[i] >= 48 && s[i] <= 57) {
26	        val = val * 10 + (s[i] - 48);
27	        i++;
28	        got = 1;
29	    }
30	
31	    if (got == 0) {
32	        // No digits consumed
33	        *end = start;
34	        return 0;
35	    }
36	
37	    *end = i;
38	    if (neg) {
39	        return 0 - val;
40	    }
41	    return val;
42	}
43	
44	// Print an integer to UART using APL underscore-negative convention.
45	// Negative numbers are printed as _N (e.g., -42 prints as _42).
46	void print_int(int n) {
47	    if (n < 0) {
48	        putchar(95);  // underscore
49	        n = 0 - n;
50	    }
51	    if (n == 0) {
52	        putchar(48);
53	        return;
54	    }
55	    char buf[8];
56	    int i = 0;
57	    while (n > 0) {
58	        buf[i] = 48 + n % 10;
59	        n = n / 10;
60	        i++;
61	    }
62	    while (i > 0) {
63	        i--;
64	        putchar(buf[i]);
65	    }
66	}
